import json
import random
from datetime import datetime
from pathlib import Path

base = Path(__file__).parent.parent
cids = json.loads((base / "content/ipfs_image_cids.json").read_text())
meta_dir = base / "metadata"
pieces = []

# Build lookup from metadata edition -> image filename
meta_to_image = {}
for mf in sorted(meta_dir.glob("*.json"), key=lambda p: int(p.stem)):
    md = json.loads(mf.read_text())
    meta_to_image[int(mf.stem)] = md.get("image", "")

for f in sorted((base / "content/lore").glob("*.json"), key=lambda p: int(p.stem)):
    d = json.loads(f.read_text())
    edition = int(f.stem)
    name = d.get("piece_name","")
    image_file = meta_to_image.get(edition, "")
    cid = cids.get(image_file, "")
    img = f"https://gateway.pinata.cloud/ipfs/{cid}" if cid else ""
    pieces.append({"name":name,"tier":d.get("tier",""),"provenance":d.get("provenance","").replace('"',"'"),"threshold":d.get("threshold_note","").replace('"',"'"),"collector":d.get("collector_meaning","").replace('"',"'"),"img":img})

# Daily random featured piece and lore quote
random.seed(datetime.now().strftime('%Y%m%d'))
featured = random.choice(pieces) if pieces else None
lore_piece = random.choice(pieces) if pieces else None

cards = ""
for p in pieces:
    cards += f'<div class="card" onclick="openModal(this)" data-name="{p["name"]}" data-tier="{p["tier"]}" data-provenance="{p["provenance"]}" data-threshold="{p["threshold"]}" data-collector="{p["collector"]}"><div class="card-img-wrap"><img src="{p["img"]}" loading="lazy" onerror="this.parentElement.style.background=\'#0a0a0f\'"></div><div class="card-overlay"><span class="card-tier">{p["tier"]}</span><span class="card-name">{p["name"]}</span></div></div>'

# Build featured piece HTML
featured_html = ""
if featured:
    featured_html = f'<section class="featured-section"><p class="featured-eyebrow">Today\'s Featured Piece</p><div class="featured-inner"><div class="featured-img"><img src="{featured["img"]}" alt="{featured["name"]}"></div><div class="featured-info"><span class="featured-tier">{featured["tier"]}</span><h2 class="featured-name">{featured["name"]}</h2><p class="featured-prov">{featured["provenance"]}</p></div></div></section>'

# Build lore teaser HTML
lore_html = ""
if lore_piece and lore_piece["threshold"]:
    lore_html = f'<section class="lore-teaser"><blockquote class="lore-quote">&ldquo;{lore_piece["threshold"]}&rdquo;</blockquote><p class="lore-attr">&mdash; from <em>{lore_piece["name"]}</em></p></section>'

